mapper.select:
select a.id, s.name as student_name, u.mobile, l.title as lesson_title, l.date, l.start_time, a.add_time as appoint_time, st.name as verify_staff, a.remark, case a.verify_state when 1 then '未审核' when 2 then '审核通过' when 3 then '已驳回' end as verify_state from appointment a left join student s on s.id = a.student_id left join user u on s.user_id = u.id left join lesson l on a.lesson_id = l.id left join staff st on a.verify_staff = st.id
and l.date >= #{startDate}
and l.date <= #{endDate}
order by l.date asc

SELECT a.id, a.verify_state AS verifyState, a.course_id AS courseId, a.add_time AS addTime, s.name AS studentName, u.mobile AS mobile, c.name AS courseName,
CONCAT(l.date, ' ', l.start_time) AS lessonTime, st.name AS verifyStaffName FROM appointment a LEFT JOIN student s ON a.student_id = s.id LEFT JOIN `user` u ON s.user_id = u.id LEFT JOIN course c ON a.course_id = c.id LEFT JOIN lesson l ON a.lesson_id = l.id LEFT JOIN staff st ON a.verify_staff = st.id
AND a.student_id IN
#{stuId}
AND a.course_id IN
#{crsId}
AND a.add_time >= #{query.startDate}
AND a.add_time <= #{query.endDate}
ORDER BY a.add_time DESC
